import { GoogleGenAI } from "@google/genai";

export const explainConcept = async (concept: string, context: string): Promise<string> => {
  // Check for API key inside the function to avoid top-level crash on app load
  const apiKey = process.env.API_KEY;

  if (!apiKey) {
    return "The AI Tutor is currently offline because no API Key was detected. \n\nTo enable AI features, please set up your API Key in the environment variables. \n\nDon't worry—the rest of your dashboard, roadmap, and tracking tools work perfectly without it!";
  }

  try {
    const ai = new GoogleGenAI({ apiKey });

    const prompt = `
      You are an expert technical tutor for a student learning software engineering.
      The student is asking about: "${concept}".
      The context of their learning path is: "${context}".

      Please provide a concise, clear, and beginner-friendly explanation (max 150 words). 
      If applicable, provide a very short code snippet in the relevant language (Python for DSA, JS/TS for Web/Mobile).
      Focus on the "Why" and "How".
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
    });

    return response.text || "I couldn't generate an explanation at this time.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Error connecting to the AI Tutor. Please check your internet connection or API quota.";
  }
};

import { initializeApp } from "firebase/app";
import { getAuth, GoogleAuthProvider, signInWithPopup, signOut, onAuthStateChanged, User } from "firebase/auth";
import { getFirestore, doc, setDoc, getDoc } from "firebase/firestore";
import { Domain } from "../types";

// !!! IMPORTANT: REPLACE THIS WITH YOUR FIREBASE PROJECT CONFIGURATION !!!
// Go to https://console.firebase.google.com/ -> Create Project -> Add Web App -> Copy Config
const firebaseConfig = {
  apiKey: "AIzaSyD-YOUR-API-KEY-HERE",
  authDomain: "your-project.firebaseapp.com",
  projectId: "your-project-id",
  storageBucket: "your-project.appspot.com",
  messagingSenderId: "123456789",
  appId: "1:123456789:web:abcdef123456"
};

// Initialize Firebase
// We wrap in a try-catch to prevent the app from crashing if config is invalid
let app, auth, db, googleProvider;

try {
  app = initializeApp(firebaseConfig);
  auth = getAuth(app);
  db = getFirestore(app);
  googleProvider = new GoogleAuthProvider();
} catch (error) {
  console.warn("Firebase not initialized. Please update services/firebase.ts with your config.");
}

export const authService = {
  signIn: async () => {
    if (!auth) throw new Error("Firebase not configured");
    try {
      const result = await signInWithPopup(auth, googleProvider);
      return result.user;
    } catch (error) {
      console.error("Error signing in", error);
      throw error;
    }
  },

  logout: async () => {
    if (!auth) return;
    try {
      await signOut(auth);
    } catch (error) {
      console.error("Error signing out", error);
    }
  },

  onUserChanged: (callback: (user: User | null) => void) => {
    if (!auth) return () => {};
    return onAuthStateChanged(auth, callback);
  }
};

export const dataService = {
  // Save only the completion status (IDs) to save bandwidth and allow syllabus updates
  saveProgress: async (userId: string, domains: Domain[]) => {
    if (!db) return;

    // Create a map of { taskId: boolean }
    const progressMap: Record<string, boolean> = {};

    domains.forEach(domain => {
      domain.sections.forEach(section => {
        section.tasks.forEach(task => {
          if (task.isCompleted) {
            progressMap[task.id] = true;
          }
        });
      });
    });

    try {
      await setDoc(doc(db, "users", userId), { 
        progress: progressMap,
        lastUpdated: new Date().toISOString() 
      }, { merge: true });
    } catch (error) {
      console.error("Error saving progress", error);
    }
  },

  loadProgress: async (userId: string): Promise<Record<string, boolean> | null> => {
    if (!db) return null;
    try {
      const docRef = doc(db, "users", userId);
      const docSnap = await getDoc(docRef);

      if (docSnap.exists()) {
        return docSnap.data().progress as Record<string, boolean>;
      }
      return null;
    } catch (error) {
      console.error("Error loading progress", error);
      return null;
    }
  }
};

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import DomainTracker from './components/DomainTracker';
import { INITIAL_DOMAINS } from './data';
import { Domain, View } from './types';
import { authService, dataService } from './services/firebase';
import { User } from 'firebase/auth';

function App() {
  const [domains, setDomains] = useState<Domain[]>(INITIAL_DOMAINS);
  const [currentView, setCurrentView] = useState<View>('dashboard');
  const [activeDomainId, setActiveDomainId] = useState<string | null>(null);
  const [user, setUser] = useState<User | null>(null);
  const [isSyncing, setIsSyncing] = useState(false);

  // Load from local storage on mount (immediate offline support)
  useEffect(() => {
    const savedData = localStorage.getItem('careerLaunchData');
    if (savedData) {
      try {
        setDomains(JSON.parse(savedData));
      } catch (e) {
        console.error("Failed to load local data", e);
      }
    }
  }, []);

  // Listen for Auth Changes and Sync
  useEffect(() => {
    const unsubscribe = authService.onUserChanged(async (currentUser) => {
      setUser(currentUser);

      if (currentUser) {
        setIsSyncing(true);
        // Load cloud progress
        const cloudProgress = await dataService.loadProgress(currentUser.uid);

        if (cloudProgress) {
          // Merge cloud progress with current domains
          setDomains(prevDomains => 
            prevDomains.map(d => ({
              ...d,
              sections: d.sections.map(s => ({
                ...s,
                tasks: s.tasks.map(t => ({
                  ...t,
                  isCompleted: cloudProgress[t.id] ?? t.isCompleted
                }))
              }))
            }))
          );
        } else {
          // New user or no cloud data: Save current local state to cloud
          await dataService.saveProgress(currentUser.uid, domains);
        }
        setIsSyncing(false);
      }
    });

    return () => unsubscribe();
  }, []);

  // Save to Local Storage + Cloud on any change
  useEffect(() => {
    // 1. Local Storage
    localStorage.setItem('careerLaunchData', JSON.stringify(domains));

    // 2. Cloud Storage (Debounced slightly ideally, but direct here for simplicity)
    if (user && !isSyncing) {
      dataService.saveProgress(user.uid, domains);
    }
  }, [domains, user]);

  const handleDomainSelect = (id: string) => {
    setActiveDomainId(id);
    setCurrentView('domain');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleBackToDashboard = () => {
    setActiveDomainId(null);
    setCurrentView('dashboard');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleToggleTask = (domainId: string, sectionId: string, taskId: string) => {
    setDomains(prevDomains => 
      prevDomains.map(d => {
        if (d.id !== domainId) return d;
        return {
          ...d,
          sections: d.sections.map(s => {
            if (s.id !== sectionId) return s;
            return {
              ...s,
              tasks: s.tasks.map(t => {
                if (t.id !== taskId) return t;
                return { ...t, isCompleted: !t.isCompleted };
              })
            };
          })
        };
      })
    );
  };

  const handleSignIn = async () => {
    try {
      await authService.signIn();
    } catch (e) {
      alert("Please update services/firebase.ts with your Firebase Config to enable syncing!");
    }
  };

  const handleSignOut = async () => {
    await authService.logout();
    // Optional: Clear local state or keep it? Keeping it is usually better UX.
  };

  const activeDomain = domains.find(d => d.id === activeDomainId);

  return (
    <Layout 
      onDashboardClick={handleBackToDashboard}
      user={user}
      onSignIn={handleSignIn}
      onSignOut={handleSignOut}
    >
      {currentView === 'dashboard' ? (
        <>
          <div className="mb-8 animate-in fade-in slide-in-from-bottom-4 duration-500 flex flex-col md:flex-row md:items-end justify-between gap-4">
            <div>
              <h2 className="text-3xl font-bold text-gray-900 tracking-tight">Your Learning Roadmap</h2>
              <p className="text-gray-500 mt-2 text-lg">Track your progress from beginner to FAANG-ready engineer.</p>
            </div>
            {user && (
              <div className="flex items-center gap-2 text-xs font-bold text-emerald-600 bg-emerald-50 px-3 py-1 rounded-full border border-emerald-100">
                <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
                Cloud Sync Active
              </div>
            )}
          </div>
          <Dashboard 
            domains={domains} 
            onSelectDomain={handleDomainSelect} 
          />
        </>
      ) : (
        activeDomain && (
          <DomainTracker 
            domain={activeDomain} 
            onBack={handleBackToDashboard}
            onToggleTask={handleToggleTask}
          />
        )
      )}
    </Layout>
  );
}

export default App;

